1	export type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	
3	export type Step = { op: string; items?: Item[]; policy?: number; incident?: unknown };
4	
5	export type Scenario = {
6	  customer: { yearsWithMHPCO: number };
7	  steps: Step[];
8	};
9	
10	export type ScenarioResult = {
11	  results: StepResult[];
12	};
13	
14	const PROCESSING_FEE = 5;
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	type StepResult = { premium?: number; payout?: number; remainingCap?: number };
26	
27	const BLOCK_SIZE = 3;
28	const BLOCK_PREMIUM = 60;
29	
30	const CURSE_SURCHARGE_RATE = 0.5;
31	const FIRST_INSURANCE_RATE = 0.1;
32	const HIGH_ENCHANTMENT_RATE = 0.3;
33	const HIGH_ENCHANTMENT_THRESHOLD = 5;
34	
35	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
36	
37	const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
38	
39	const groupKeyFor = (item: Item, index: number): string =>
40	  COMPONENT_TYPES.has(item.type) ? item.type : `item:${index}`;
41	
42	const groupItemsForPricing = (items: Item[]): Item[][] => {
43	  const groups = new Map<string, Item[]>();
44	  items.forEach((item, index) => {
45	    const key = groupKeyFor(item, index);
46	    const group = groups.get(key) ?? [];
47	    group.push(item);
48	    groups.set(key, group);
49	  });
50	  return [...groups.values()];
51	};
52	
53	const premiumForGroup = (group: Item[]): number =>
54	  group.length === BLOCK_SIZE
55	    ? BLOCK_PREMIUM
56	    : group.reduce((total, item) => total + basePremiumFor(item), 0);
57	
58	const totalBasePremiumFor = (items: Item[]): number =>
59	  groupItemsForPricing(items).reduce((total, group) => total + premiumForGroup(group), 0);
60	
61	const curseSurchargeFor = (items: Item[]): number =>
62	  items.reduce(
63	    (total, item) => (item.cursed ? total + basePremiumFor(item) * CURSE_SURCHARGE_RATE : total),
64	    0,
65	  );
66	
67	const firstInsuranceSurchargeFor = (base: number): number => base * FIRST_INSURANCE_RATE;
68	
69	const highEnchantmentSurchargeFor = (items: Item[]): number =>
70	  items.reduce(
71	    (total, item) =>
72	      (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
73	        ? total + basePremiumFor(item) * HIGH_ENCHANTMENT_RATE
74	        : total,
75	    0,
76	  );
77	
78	const quotePremium = (items: Item[]): number => {
79	  const base = totalBasePremiumFor(items);
80	  const curseSurcharge = curseSurchargeFor(items);
81	  const highEnchantmentSurcharge = highEnchantmentSurchargeFor(items);
82	  const firstInsuranceSurcharge = firstInsuranceSurchargeFor(base);
83	  return Math.ceil(
84	    base + curseSurcharge + highEnchantmentSurcharge + firstInsuranceSurcharge + PROCESSING_FEE,
85	  );
86	};
87	
88	const processStep = ({ items = [] }: Step): StepResult => ({ premium: quotePremium(items) });
89	
90	export const runScenario = (scenario: Scenario): ScenarioResult => ({
91	  results: scenario.steps.map(processStep),
92	});
